{
  "name": "Astro Companion",
  "description": "An essential web application for amateur astronomers, providing local astronomical data and a comprehensive telescope calculator. Features a night mode to preserve night vision.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useCallback } from 'react';
import { Dashboard } from './components/Dashboard';
import { TelescopeCalculator } from './components/TelescopeCalculator';
import { DevelopmentIdeas } from './components/DevelopmentIdeas';
import { SunIcon, MoonIcon, TelescopeIcon, DashboardIcon, LightbulbIcon } from './components/Icons';
import type { LocationData } from './types';

type View = 'dashboard' | 'calculator' | 'ideas';

const App: React.FC = () => {
  const [isNightMode, setIsNightMode] = useState(false);
  const [currentView, setCurrentView] = useState<View>('dashboard');

  const toggleNightMode = useCallback(() => {
    setIsNightMode(prev => !prev);
  }, []);

  const NavButton = ({ view, label, icon }: { view: View; label: string; icon: JSX.Element }) => (
    <button
      onClick={() => setCurrentView(view)}
      className={`flex flex-col sm:flex-row items-center justify-center sm:justify-start sm:px-4 py-3 w-full text-sm font-medium rounded-lg transition-colors duration-200 ${
        currentView === view
          ? isNightMode ? 'bg-red-900/50 text-red-300' : 'bg-blue-600 text-white'
          : isNightMode ? 'text-red-400 hover:bg-red-900/50 hover:text-red-300' : 'text-gray-300 hover:bg-gray-700 hover:text-white'
      }`}
    >
      {icon}
      <span className="mt-1 sm:mt-0 sm:ml-3">{label}</span>
    </button>
  );

  const renderView = () => {
    switch (currentView) {
      case 'calculator':
        return <TelescopeCalculator isNightMode={isNightMode} />;
      case 'ideas':
        return <DevelopmentIdeas isNightMode={isNightMode} />;
      case 'dashboard':
      default:
        return <Dashboard isNightMode={isNightMode} />;
    }
  };

  const bgColor = isNightMode ? 'bg-black' : 'bg-gray-900';
  const textColor = isNightMode ? 'text-red-500' : 'text-gray-200';

  return (
    <div className={`min-h-screen w-full flex flex-col md:flex-row ${bgColor} ${textColor} font-sans transition-colors duration-300`}>
      <header className="md:w-64 md:flex-shrink-0 md:flex md:flex-col p-4 border-b md:border-b-0 md:border-r ${isNightMode ? 'border-red-800' : 'border-gray-700'} bg-opacity-20 ${isNightMode ? 'bg-red-900/10' : 'bg-gray-800'}`}>
        <div className="flex justify-between items-center mb-6">
          <h1 className={`text-2xl font-bold ${isNightMode ? 'text-red-400' : 'text-white'}`}>
            Astro Companion
          </h1>
          <button onClick={toggleNightMode} className={`p-2 rounded-full ${isNightMode ? 'text-red-400 hover:bg-red-900/50' : 'text-yellow-400 hover:bg-gray-700'}`}>
            {isNightMode ? <SunIcon className="w-6 h-6" /> : <MoonIcon className="w-6 h-6" />}
          </button>
        </div>
        <nav className="flex md:flex-col justify-around md:justify-start md:space-y-2">
          <NavButton view="dashboard" label="Dashboard" icon={<DashboardIcon className="w-5 h-5" />} />
          <NavButton view="calculator" label="Calculator" icon={<TelescopeIcon className="w-5 h-5" />} />
          <NavButton view="ideas" label="Dev Ideas" icon={<LightbulbIcon className="w-5 h-5" />} />
        </nav>
      </header>

      <main className="flex-grow p-4 sm:p-6 lg:p-8 overflow-y-auto">
        {renderView()}
      </main>
    </div>
  );
};

export default App;

export interface LocationData {
  latitude: number;
  longitude: number;
}

import { useState, useEffect } from 'react';
import type { LocationData } from '../types';

export const useGeolocation = () => {
  const [location, setLocation] = useState<LocationData | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState<boolean>(true);

  useEffect(() => {
    if (!navigator.geolocation) {
      setError('Geolocation is not supported by your browser.');
      setLoading(false);
      return;
    }

    const handleSuccess = (position: GeolocationPosition) => {
      setLocation({
        latitude: position.coords.latitude,
        longitude: position.coords.longitude,
      });
      setLoading(false);
    };

    const handleError = (error: GeolocationPositionError) => {
      setError(`Error getting location: ${error.message}`);
      setLoading(false);
    };

    navigator.geolocation.getCurrentPosition(handleSuccess, handleError, {
      enableHighAccuracy: true,
      timeout: 10000,
      maximumAge: 0,
    });

  }, []);

  return { location, error, loading };
};

import React, { useState, useEffect } from 'react';
import { useGeolocation } from '../hooks/useGeolocation';
import { ClockIcon, GlobeIcon, CalendarIcon, CompassIcon } from './Icons';

interface DashboardProps {
  isNightMode: boolean;
}

const InfoCard = ({ title, value, icon, isNightMode, loading }: { title: string; value: string; icon: JSX.Element; isNightMode: boolean; loading?: boolean }) => {
  const cardBg = isNightMode ? 'bg-red-900/20 border-red-800/50' : 'bg-gray-800 border-gray-700';
  const titleColor = isNightMode ? 'text-red-400' : 'text-gray-400';
  const valueColor = isNightMode ? 'text-red-300' : 'text-white';
  const iconColor = isNightMode ? 'text-red-500' : 'text-blue-500';

  return (
    <div className={`p-4 rounded-lg border ${cardBg} transition-colors duration-300`}>
      <div className="flex items-center">
        <div className={`mr-4 p-2 rounded-full ${isNightMode ? 'bg-red-900/50' : 'bg-gray-700'}`}>
           <span className={iconColor}>{icon}</span>
        </div>
        <div>
          <h3 className={`text-sm font-medium ${titleColor}`}>{title}</h3>
          {loading ? (
             <div className={`h-6 mt-1 rounded ${isNightMode ? 'bg-red-800/50' : 'bg-gray-700'} animate-pulse w-3/4`}></div>
          ) : (
            <p className={`text-xl font-semibold ${valueColor}`}>{value}</p>
          )}
        </div>
      </div>
    </div>
  );
};


export const Dashboard: React.FC<DashboardProps> = ({ isNightMode }) => {
  const { location, error: geoError, loading: geoLoading } = useGeolocation();
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const getJulianDate = (date: Date) => {
    return (date.getTime() / 86400000) + 2440587.5;
  };

  const formatCoordinate = (coord: number, type: 'lat' | 'lon') => {
    const direction = coord >= 0 ? (type === 'lat' ? 'N' : 'E') : (type === 'lat' ? 'S' : 'W');
    return `${Math.abs(coord).toFixed(4)}° ${direction}`;
  };

  return (
    <div className="animate-fade-in">
      <h2 className={`text-3xl font-bold mb-6 ${isNightMode ? 'text-red-400' : 'text-white'}`}>Local Sky Data</h2>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        <InfoCard title="Local Time" value={time.toLocaleTimeString()} icon={<ClockIcon className="w-6 h-6"/>} isNightMode={isNightMode} />
        <InfoCard title="UTC" value={time.toUTCString().split(' ')[4]} icon={<GlobeIcon className="w-6 h-6"/>} isNightMode={isNightMode} />
        <InfoCard title="Julian Date" value={getJulianDate(time).toFixed(5)} icon={<CalendarIcon className="w-6 h-6"/>} isNightMode={isNightMode} />
        <InfoCard title="Latitude" value={location ? formatCoordinate(location.latitude, 'lat') : (geoError || '...')} icon={<CompassIcon className="w-6 h-6"/>} isNightMode={isNightMode} loading={geoLoading} />
        <InfoCard title="Longitude" value={location ? formatCoordinate(location.longitude, 'lon') : (geoError || '...')} icon={<CompassIcon className="w-6 h-6"/>} isNightMode={isNightMode} loading={geoLoading} />
      </div>
       {geoError && (
        <div className={`mt-6 p-4 rounded-lg text-sm ${isNightMode ? 'bg-red-900/30 text-red-300 border border-red-800' : 'bg-yellow-900/30 text-yellow-300 border border-yellow-800'}`}>
          <strong>Geolocation Error:</strong> {geoError}. Please ensure you have granted location permissions.
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';

interface TelescopeCalculatorProps {
  isNightMode: boolean;
}

const InputField = ({ label, value, onChange, unit, min, max, step }: { label: string; value: number; onChange: (val: number) => void; unit: string; min: number; max: number; step: number; }) => (
  <div className="mb-4">
    <label className="block text-sm font-medium mb-1">{label}</label>
    <div className="flex items-center space-x-2">
      <input
        type="range"
        min={min}
        max={max}
        step={step}
        value={value}
        onChange={(e) => onChange(parseFloat(e.target.value))}
        className="w-full h-2 bg-gray-600 rounded-lg appearance-none cursor-pointer accent-blue-500"
        style={ { accentColor: 'red' } }
      />
       <input
        type="number"
        value={value}
        onChange={(e) => onChange(parseFloat(e.target.value))}
        className="w-24 p-2 text-center bg-gray-700 border border-gray-600 rounded-md text-white"
      />
      <span className="w-8 text-sm">{unit}</span>
    </div>
  </div>
);

const ResultField = ({ label, value, unit, description, isNightMode }: { label: string; value: string; unit?: string; description: string; isNightMode: boolean; }) => (
    <div className={`p-3 rounded-md mb-2 ${isNightMode ? 'bg-red-900/20' : 'bg-gray-800'}`}>
        <div className="flex justify-between items-baseline">
            <span className={`text-sm font-medium ${isNightMode ? 'text-red-400' : 'text-gray-400'}`}>{label}</span>
            <span className={`text-lg font-bold ${isNightMode ? 'text-red-300' : 'text-white'}`}>{value} {unit}</span>
        </div>
        <p className={`text-xs mt-1 ${isNightMode ? 'text-red-500' : 'text-gray-500'}`}>{description}</p>
    </div>
);

export const TelescopeCalculator: React.FC<TelescopeCalculatorProps> = ({ isNightMode }) => {
  const [aperture, setAperture] = useState(150); // mm
  const [focalLength, setFocalLength] = useState(750); // mm
  const [eyepieceFocalLength, setEyepieceFocalLength] = useState(10); // mm
  const [eyepieceAFOV, setEyepieceAFOV] = useState(52); // degrees

  const calculations = useMemo(() => {
    if (aperture <= 0 || focalLength <= 0 || eyepieceFocalLength <= 0) {
      return {};
    }

    const focalRatio = focalLength / aperture;
    const magnification = focalLength / eyepieceFocalLength;
    const exitPupil = aperture / magnification;
    const trueFOV = eyepieceAFOV / magnification;
    const maxMagnification = aperture * 2;
    const minMagnification = aperture / 7;
    const dawesLimit = 116 / aperture;
    const limitingMagnitude = 7.7 + 5 * Math.log10(aperture / 10);

    return {
      focalRatio,
      magnification,
      exitPupil,
      trueFOV,
      maxMagnification,
      minMagnification,
      dawesLimit,
      limitingMagnitude
    };
  }, [aperture, focalLength, eyepieceFocalLength, eyepieceAFOV]);

  const containerBg = isNightMode ? 'bg-red-900/20 border-red-800/50' : 'bg-gray-800/50 border-gray-700';

  return (
    <div className="animate-fade-in">
        <h2 className={`text-3xl font-bold mb-6 ${isNightMode ? 'text-red-400' : 'text-white'}`}>Telescope Calculator</h2>
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <div className={`p-6 rounded-lg border ${containerBg}`}>
                <h3 className={`text-xl font-semibold mb-4 border-b pb-2 ${isNightMode ? 'border-red-800 text-red-400' : 'border-gray-600 text-white'}`}>Telescope & Eyepiece Specs</h3>
                <InputField label="Telescope Aperture" value={aperture} onChange={setAperture} unit="mm" min={50} max={500} step={1} />
                <InputField label="Telescope Focal Length" value={focalLength} onChange={setFocalLength} unit="mm" min={200} max={4000} step={10} />
                <InputField label="Eyepiece Focal Length" value={eyepieceFocalLength} onChange={setEyepieceFocalLength} unit="mm" min={2} max={50} step={0.5} />
                <InputField label="Eyepiece Apparent FOV" value={eyepieceAFOV} onChange={setEyepieceAFOV} unit="°" min={30} max={120} step={1} />
            </div>
            <div className={`p-6 rounded-lg border ${containerBg}`}>
                <h3 className={`text-xl font-semibold mb-4 border-b pb-2 ${isNightMode ? 'border-red-800 text-red-400' : 'border-gray-600 text-white'}`}>Calculated Values</h3>
                <ResultField isNightMode={isNightMode} label="Focal Ratio (f/)" value={calculations.focalRatio?.toFixed(1) ?? 'N/A'} description="Speed and field of view of the telescope." />
                <ResultField isNightMode={isNightMode} label="Magnification" value={calculations.magnification?.toFixed(0) ?? 'N/A'} unit="x" description="How much larger the object appears." />
                <ResultField isNightMode={isNightMode} label="Exit Pupil" value={calculations.exitPupil?.toFixed(1) ?? 'N/A'} unit="mm" description="Light beam diameter. Match to your eye's pupil (2-7mm)." />
                <ResultField isNightMode={isNightMode} label="True Field of View (TFOV)" value={calculations.trueFOV?.toFixed(2) ?? 'N/A'} unit="°" description="The angular size of the sky visible." />
                <ResultField isNightMode={isNightMode} label="Max Useful Magnification" value={calculations.maxMagnification?.toFixed(0) ?? 'N/A'} unit="x" description="Theoretical limit before image degrades." />
                <ResultField isNightMode={isNightMode} label="Min Useful Magnification" value={calculations.minMagnification?.toFixed(0) ?? 'N/A'} unit="x" description="Lowest power before exit pupil is too large." />
                <ResultField isNightMode={isNightMode} label="Resolving Power (Dawes' Limit)" value={calculations.dawesLimit?.toFixed(2) ?? 'N/A'} unit="arcsec" description="Ability to distinguish close objects. Lower is better." />
                <ResultField isNightMode={isNightMode} label="Limiting Stellar Magnitude" value={calculations.limitingMagnitude?.toFixed(1) ?? 'N/A'} description="Faintest star visible through the telescope. Higher is better." />
            </div>
        </div>
    </div>
  );
};

import React from 'react';
import { CheckCircleIcon } from './Icons';

interface DevelopmentIdeasProps {
  isNightMode: boolean;
}

const IdeaItem = ({ title, description, isNightMode }: { title: string; description: string; isNightMode: boolean; }) => (
  <li className={`p-4 rounded-lg flex items-start space-x-4 ${isNightMode ? 'bg-red-900/20' : 'bg-gray-800'}`}>
    <div className={`flex-shrink-0 mt-1 ${isNightMode ? 'text-red-400' : 'text-blue-500'}`}>
      <CheckCircleIcon className="w-6 h-6" />
    </div>
    <div>
      <h4 className={`font-semibold ${isNightMode ? 'text-red-300' : 'text-white'}`}>{title}</h4>
      <p className={`text-sm ${isNightMode ? 'text-red-400' : 'text-gray-400'}`}>{description}</p>
    </div>
  </li>
);

export const DevelopmentIdeas: React.FC<DevelopmentIdeasProps> = ({ isNightMode }) => {
  const ideas = [
    {
      title: 'Astronomical Weather Forecast',
      description: 'Integrate a weather service API to show cloud cover, atmospheric seeing, transparency, and moon phase for the user\'s location.'
    },
    {
      title: 'Object Catalog & Planner',
      description: 'Add a searchable catalog of Messier, NGC, and other deep-sky objects. Show their current position, visibility, and allow users to create an observation plan for the night.'
    },
    {
      title: 'Observation Log',
      description: 'A digital logbook for users to record their observations, including object name, date, time, equipment used, and notes or sketches.'
    },
    {
      title: 'Polar Alignment Assistant',
      description: 'A tool to help users with equatorial mounts to accurately polar align their telescope using their phone\'s camera and gyroscope.'
    },
    {
      title: 'Push Notifications',
      description: 'Allow users to subscribe to alerts for astronomical events like meteor showers, ISS passes, or planetary conjunctions visible from their location.'
    },
    {
      title: 'Equipment Database',
      description: 'Let users save their telescopes, eyepieces, and other gear to quickly load them into the calculator instead of entering specs manually each time.'
    }
  ];

  return (
    <div className="animate-fade-in">
      <h2 className={`text-3xl font-bold mb-6 ${isNightMode ? 'text-red-400' : 'text-white'}`}>Future Development Ideas</h2>
      <p className={`mb-6 ${isNightMode ? 'text-red-400' : 'text-gray-400'}`}>
        This application is built to be modular. Here are some ideas for future features to enhance its utility for amateur astronomers:
      </p>
      <ul className="space-y-4">
        {ideas.map((idea, index) => (
          <IdeaItem key={index} title={idea.title} description={idea.description} isNightMode={isNightMode} />
        ))}
      </ul>
    </div>
  );
};

