export const Dashboard: React.FC<DashboardProps> = ({ isNightMode }) => {
  const { location, error: geoError, loading: geoLoading } = useGeolocation();
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const getJulianDate = (date: Date) => {
    return (date.getTime() / 86400000) + 2440587.5;
  };

  const formatCoordinate = (coord: number, type: 'lat' | 'lon') => {
    const direction = coord >= 0 ? (type === 'lat' ? 'N' : 'E') : (type === 'lat' ? 'S' : 'W');
    return `${Math.abs(coord).toFixed(4)}° ${direction}`;
  };

  return (
    <div className="animate-fade-in">
      <h2 className={`text-3xl font-bold mb-6 ${isNightMode ? 'text-red-400' : 'text-white'}`}>Local Sky Data</h2>
