        <InfoCard title="UTC" value={time.toUTCString().split(' ')[4]} icon={<GlobeIcon className="w-6 h-6"/>} isNightMode={isNightMode} />
        <InfoCard title="Julian Date" value={getJulianDate(time).toFixed(5)} icon={<CalendarIcon className="w-6 h-6"/>} isNightMode={isNightMode} />
        <InfoCard title="Latitude" value={location ? formatCoordinate(location.latitude, 'lat') : (geoError || '...')} icon={<CompassIcon className="w-6 h-6"/>} isNightMode={isNightMode} loading={geoLoading} />
