export const TelescopeCalculator: React.FC<TelescopeCalculatorProps> = ({ isNightMode }) => {
  const [aperture, setAperture] = useState(150); // mm
  const [focalLength, setFocalLength] = useState(750); // mm
  const [eyepieceFocalLength, setEyepieceFocalLength] = useState(10); // mm
  const [eyepieceAFOV, setEyepieceAFOV] = useState(52); // degrees

  const calculations = useMemo(() => {
    if (aperture <= 0 || focalLength <= 0 || eyepieceFocalLength <= 0) {
      return {};
    }

    const focalRatio = focalLength / aperture;
    const magnification = focalLength / eyepieceFocalLength;
    const exitPupil = aperture / magnification;
    const trueFOV = eyepieceAFOV / magnification;
    const maxMagnification = aperture * 2;
    const minMagnification = aperture / 7;
    const dawesLimit = 116 / aperture;
    const limitingMagnitude = 7.7 + 5 * Math.log10(aperture / 10);

    return {
      focalRatio,
      magnification,
      exitPupil,
      trueFOV,
      maxMagnification,
      minMagnification,
      dawesLimit,
      limitingMagnitude
    };
  }, [aperture, focalLength, eyepieceFocalLength, eyepieceAFOV]);

  const containerBg = isNightMode ? 'bg-red-900/20 border-red-800/50' : 'bg-gray-800/50 border-gray-700';

  return (
    <div className="animate-fade-in">
        <h2 className={`text-3xl font-bold mb-6 ${isNightMode ? 'text-red-400' : 'text-white'}`}>Távcső Kalkulátor</h2>
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <div className={`p-6 rounded-lg border ${containerBg}`}>
                <h3 className={`text-xl font-semibold mb-4 border-b pb-2 ${isNightMode ? 'border-red-800 text-red-400' : 'border-gray-600 text-white'}`}>Távcső és Okulár Adatok</h3>
                <InputField label="Távcső átmérő" value={aperture} onChange={setAperture} unit="mm" min={50} max={1000} step={1} />
                <InputField label="Távcső fókusz" value={focalLength} onChange={setFocalLength} unit="mm" min={200} max={5000} step={10} />
                <InputField label="Okulár fókusz" value={eyepieceFocalLength} onChange={setEyepieceFocalLength} unit="mm" min={2} max={50} step={0.5} />
                <InputField label="Okulár látómező" value={eyepieceAFOV} onChange={setEyepieceAFOV} unit="°" min={30} max={120} step={1} />
            </div>
            <div className={`p-6 rounded-lg border ${containerBg}`}>
                <h3 className={`text-xl font-semibold mb-4 border-b pb-2 ${isNightMode ? 'border-red-800 text-red-400' : 'border-gray-600 text-white'}`}>Számított Értékek</h3>
                <ResultField isNightMode={isNightMode} label="Fókuszarány (f/)" value={calculations.focalRatio?.toFixed(1) ?? 'N/A'} description="A távcső 'fényereje' és látómezeje." />
                <ResultField isNightMode={isNightMode} label="Nagyítás" value={calculations.magnification?.toFixed(0) ?? 'N/A'} unit="x" description="Ennyiszer nagyobbnak látszik az objektum." />
                <ResultField isNightMode={isNightMode} label="Kilépő pupilla" value={calculations.exitPupil?.toFixed(1) ?? 'N/A'} unit="mm" description="A fénykéve átmérője. Ideális: 2-7mm." />
                <ResultField isNightMode={isNightMode} label="Valós látómező (TFOV)" value={calculations.trueFOV?.toFixed(2) ?? 'N/A'} unit="°" description="A látható égboltszelet szögmérete." />
                <ResultField isNightMode={isNightMode} label="Max. hasznos nagyítás" value={calculations.maxMagnification?.toFixed(0) ?? 'N/A'} unit="x" description="Elméleti határ, ami felett a kép minősége romlik." />
                <ResultField isNightMode={isNightMode} label="Min. hasznos nagyítás" value={calculations.minMagnification?.toFixed(0) ?? 'N/A'} unit="x" description="Alsó határ, ami alatt a kilépő pupilla túl nagy." />
                <ResultField isNightMode={isNightMode} label="Felbontóképesség (Dawes-limit)" value={calculations.dawesLimit?.toFixed(2) ?? 'N/A'} unit="arcsec" description="Közeli objektumok megkülönböztetése. Az alacsonyabb jobb." />
                <ResultField isNightMode={isNightMode} label="Határmagnitúdó" value={calculations.limitingMagnitude?.toFixed(1) ?? 'N/A'} description="A leghalványabb látható csillag. A magasabb jobb." />
            </div>
        </div>
    </div>
  );
};

