import React from 'react';

interface MoonPhaseIconProps {
  phase: number; // 0 (new) to 1 (new)
  isNightMode: boolean;
}

export const MoonPhaseIcon: React.FC<MoonPhaseIconProps> = ({ phase, isNightMode }) => {
  const size = 64;
  const r = size / 2 - 2;

  const fgColor = isNightMode ? '#fca5a5' : '#e5e7eb'; // red-300 or gray-200
  const bgColor = isNightMode ? 'rgba(127, 29, 29, 0.5)' : '#374151'; // red-900/50 or gray-700

  // Calculate the x-offset for the terminator
  // Phase 0.0: new moon (all dark)
  // Phase 0.25: first quarter (right half lit)
  // Phase 0.5: full moon (all lit)
  // Phase 0.75: last quarter (left half lit)
  const cx = size / 2;
  const cy = size / 2;

  // d is the path for the lit part of the moon
  let d;
  const x = (phase - 0.5) * 2 * r; // x position of the terminator's center

  if (phase <= 0.5) {
    // Waxing
    d = `M${cx},${cy - r} 
         A${r},${r} 0 1,1 ${cx},${cy + r}
         A${Math.abs(x)},${r} 0 1,0 ${cx},${cy - r} Z`;
  } else {
    // Waning
    d = `M${cx},${cy - r} 
         A${r},${r} 0 1,0 ${cx},${cy + r}
         A${Math.abs(x)},${r} 0 1,1 ${cx},${cy - r} Z`;
  }

  // Handle full and new moon edge cases for a perfect circle
  if (phase === 0.5) {
     d = `M${cx},${cy - r} A${r},${r} 0 1,1 ${cx-0.01},${cy - r} Z`; // A full circle
  }

  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      {/* Dark background of the moon */}
      <circle cx={cx} cy={cy} r={r} fill={bgColor} />
      {/* Lit part of the moon */}
      {phase > 0.01 && phase < 0.99 && (
        <path d={d} fill={fgColor} />
      )}
    </svg>
  );
};

