  const [typeFilter, setTypeFilter] = useState('');
  const [filteredObjects, setFilteredObjects] = useState(messierObjects);

  const objectTypes = [...new Set(messierObjects.map(obj => obj.type))];

  useEffect(() => {
    let results = messierObjects;
    if (searchTerm) {
      results = results.filter(obj => 
        obj.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
        (obj.name && obj.name.toLowerCase().includes(searchTerm.toLowerCase()))
      );
    }
    if (typeFilter) {
      results = results.filter(obj => obj.type === typeFilter);
    }
    setFilteredObjects(results);
  }, [searchTerm, typeFilter]);

  const cardBg = isNightMode ? 'bg-red-900/20 border-red-800/50' : 'bg-gray-800/50 border-gray-700';
  const inputStyle = "w-full p-2 rounded-md bg-gray-700 border-gray-600 text-white";

  return (
    <div className="animate-fade-in">
      <h2 className={`text-3xl font-bold mb-6 ${isNightMode ? 'text-red-400' : 'text-white'}`}>Messier Katalógus</h2>
      <div className={`p-4 rounded-lg border ${cardBg} mb-6 flex flex-col sm:flex-row gap-4`}>
        <input 
          type="text" 
          placeholder="Keresés (pl. M31, Andromeda)..." 
          value={searchTerm} 
          onChange={e => setSearchTerm(e.target.value)} 
          className={inputStyle}
        />
        <select value={typeFilter} onChange={e => setTypeFilter(e.target.value)} className={inputStyle}>
            <option value="">Minden típus</option>
            {objectTypes.map(type => <option key={type} value={type}>{type}</option>)}
        </select>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-sm text-left">
          <thead className={`${isNightMode ? 'text-red-300' : 'text-gray-300'}`}>
            <tr>
              <th className="p-2">ID</th>
              <th className="p-2">Név</th>
              <th className="p-2">Típus</th>
              <th className="p-2">Csillagkép</th>
            </tr>
          </thead>
          <tbody>
            {filteredObjects.map(obj => (
              <tr key={obj.id} className={`border-t ${isNightMode ? 'border-red-800/50' : 'border-gray-700'}`}>
                <td className="p-2 font-bold">{obj.id}</td>
                <td className="p-2">{obj.name}</td>
                <td className="p-2">{obj.type}</td>
                <td className="p-2">{obj.constellation}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

