          <NavButton view="astrophoto" label="Asztrofotós Segédlet" icon={<CameraIcon className="w-5 h-5" />} />
          <NavButton view="ideas" label="Fejlesztési Ötletek" icon={<LightbulbIcon className="w-5 h-5" />} />
