import React, { useState, useEffect } from 'react';
import { useLocalStorage } from '../hooks/useLocalStorage';
import { allDeepSkyObjects } from '../data/deepsky';
import { AstroObject } from '../types';
import { TrashIcon } from './Icons';

interface ObservationPlannerProps {
  isNightMode: boolean;
}

export const ObservationPlanner: React.FC<ObservationPlannerProps> = ({ isNightMode }) => {
  const [plan, setPlan] = useLocalStorage<AstroObject[]>('observationPlan', []);
  const [searchTerm, setSearchTerm] = useState('');
  const [availableObjects, setAvailableObjects] = useState<AstroObject[]>([]);

  useEffect(() => {
    const planIds = new Set(plan.map(p => p.id));
    const filtered = allDeepSkyObjects.filter(obj => 
      !planIds.has(obj.id) &&
      (obj.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
       obj.name.toLowerCase().includes(searchTerm.toLowerCase()))
    );
    setAvailableObjects(filtered);
  }, [searchTerm, plan]);

  const addToPlan = (obj: AstroObject) => {
    setPlan([...plan, obj]);
  };

  const removeFromPlan = (objId: string) => {
    setPlan(plan.filter(obj => obj.id !== objId));
  };

  const cardBg = isNightMode ? 'bg-red-900/20 border-red-800/50' : 'bg-gray-800/50 border-gray-700';
  const inputStyle = "w-full p-2 rounded-md bg-gray-700 border-gray-600 text-white";

  return (
    <div className="animate-fade-in">
      <h2 className={`text-3xl font-bold mb-6 ${isNightMode ? 'text-red-400' : 'text-white'}`}>Észlelési Tervező</h2>
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Available Objects */}
        <div className={`p-4 rounded-lg border ${cardBg}`}>
          <h3 className="text-xl font-semibold mb-4">Elérhető Objektumok</h3>
          <input 
            type="text" 
            placeholder="Objektum keresése..." 
            value={searchTerm} 
            onChange={e => setSearchTerm(e.target.value)} 
            className={`${inputStyle} mb-4`}
          />
          <ul className="h-96 overflow-y-auto space-y-2">
            {availableObjects.map(obj => (
              <li key={obj.id} className="flex justify-between items-center p-2 bg-gray-800 rounded">
                <div>
                  <span className="font-bold">{obj.id}</span>
                  <span className="text-sm text-gray-400 ml-2">{obj.name}</span>
                </div>
                <button onClick={() => addToPlan(obj)} className={`px-2 py-1 text-xs rounded ${isNightMode ? 'bg-red-600' : 'bg-blue-600'} text-white`}>Hozzáad</button>
              </li>
            ))}
          </ul>
        </div>
        {/* Current Plan */}
        <div className={`p-4 rounded-lg border ${cardBg}`}>
          <h3 className="text-xl font-semibold mb-4">Észlelési Terv</h3>
           <ul className="h-96 overflow-y-auto space-y-2">
            {plan.length === 0 && <p className="text-sm text-gray-400 text-center mt-4">A terved üres. Adj hozzá objektumokat a bal oldali listából.</p>}
            {plan.map(obj => (
              <li key={obj.id} className="flex justify-between items-center p-2 bg-gray-800 rounded">
                <div>
                  <span className="font-bold">{obj.id}</span>
                  <span className="text-sm text-gray-400 ml-2">{obj.name}</span>
                </div>
                <button onClick={() => removeFromPlan(obj.id)} className="text-red-500 hover:text-red-400"><TrashIcon className="w-5 h-5"/></button>
              </li>
            ))}
          </ul>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useGeolocation } from '../hooks/useGeolocation';
import { useSkyPosition } from '../hooks/useSkyPosition';
import { allDeepSkyObjects } from '../data/deepsky';
import { AstroObject } from '../types';

interface StarChartProps {
  isNightMode: boolean;
}

const ChartObject = ({ obj, location, size }: { obj: AstroObject, location: any, size: number }) => {
    const { alt, az } = useSkyPosition(obj.ra, obj.dec, location);

    if (alt === null || az === null || alt < 0) return null;

    const r = (90 - alt) / 90 * (size / 2 - 10);
    const angle = (az - 180) * (Math.PI / 180);

    const x = size / 2 + r * Math.sin(angle);
    const y = size / 2 + r * Math.cos(angle);

    const magSize = Math.max(1, 6 - obj.magnitude);

    return (
        <g transform={`translate(${x}, ${y})`}>
            <circle r={magSize} fill="white" opacity="0.8" />
            <text x={magSize + 2} y="3" fill="gray" fontSize="8">{obj.id}</text>
        </g>
    );
};

export const StarChart: React.FC<StarChartProps> = ({ isNightMode }) => {
  const { location } = useGeolocation();
  const [size, setSize] = useState(500);

  useEffect(() => {
      const updateSize = () => {
          const container = document.getElementById('chart-container');
          if (container) {
              setSize(Math.min(container.clientWidth, window.innerHeight * 0.7));
          }
      };
      updateSize();
      window.addEventListener('resize', updateSize);
      return () => window.removeEventListener('resize', updateSize);
  }, []);

  const cardBg = isNightMode ? 'bg-red-900/20 border-red-800/50' : 'bg-black border-red-800/50';
  const textColor = isNightMode ? 'text-red-500' : 'text-gray-400';

  return (
    <div className="animate-fade-in">
      <h2 className={`text-3xl font-bold mb-6 ${isNightMode ? 'text-red-400' : 'text-white'}`}>Interaktív Csillagtérkép (Béta)</h2>
      <div id="chart-container" className={`w-full p-4 rounded-lg border ${cardBg} flex justify-center items-center`}>
        <svg width={size} height={size}>
            <circle cx={size/2} cy={size/2} r={size/2-1} stroke={isNightMode ? '#991b1b' : '#374151'} strokeWidth="2" fill="none" />
            <text x="50%" y={size/2 - size/2.2} textAnchor="middle" fill={textColor} fontSize="12">É</text>
            <text x="50%" y={size/2 + size/2.2 + 10} textAnchor="middle" fill={textColor} fontSize="12">D</text>
            <text x={size/2 - size/2.2 - 5} y="50%" dominantBaseline="middle" fill={textColor} fontSize="12">K</text>
            <text x={size/2 + size/2.2 + 5} y="50%" dominantBaseline="middle" fill={textColor} fontSize="12">Ny</text>

            {location && allDeepSkyObjects.map(obj => (
                <ChartObject key={obj.id} obj={obj} location={location} size={size} />
            ))}
        </svg>
      </div>
       <p className={`text-xs text-center mt-2 ${textColor}`}>
            A térkép a zenitet (fejünk feletti pont) ábrázolja a középpontban, a kör széle a horizont.
       </p>
    </div>
  );
};

