import React from 'react';

interface MoonPhaseIconProps {
  phase: number; // 0 (new) to 1 (new)
  isNightMode: boolean;
}

export const MoonPhaseIcon: React.FC<MoonPhaseIconProps> = ({ phase, isNightMode }) => {
  const size = 64;
  const r = size / 2 - 2;
  const cx = size / 2;
  const cy = size / 2;
  const clipId = `moon-clip-${Math.random()}`;

  const fgColor = isNightMode ? '#fca5a5' : '#e5e7eb'; // red-300 or gray-200
  const bgColor = isNightMode ? 'rgba(127, 29, 29, 0.5)' : '#374151'; // red-900/50 or gray-700

  const angle = phase * 2 * Math.PI;
  const terminatorX = cx - r * Math.cos(angle);
  const terminatorRx = Math.abs(r * Math.cos(angle));

  // Path for the lit part
  let litPath;
  if (phase === 0) { // New Moon
    litPath = '';
  } else if (phase === 0.5) { // Full Moon
    litPath = `M${cx - r},${cy} a${r},${r} 0 1,0 ${2 * r},0 a${r},${r} 0 1,0 -${2 * r},0`;
  } else if (phase < 0.5) { // Waxing
    litPath = `
      M${cx},${cy - r}
      A${r},${r} 0 0,1 ${cx},${cy + r}
      A${terminatorRx},${r} 0 0,0 ${cx},${cy - r}
    `;
  } else { // Waning
    litPath = `
      M${cx},${cy - r}
      A${r},${r} 0 0,0 ${cx},${cy + r}
      A${terminatorRx},${r} 0 0,1 ${cx},${cy - r}
    `;
  }

  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      <defs>
        <clipPath id={clipId}>
          <circle cx={cx} cy={cy} r={r} />
        </clipPath>
      </defs>

      <g clipPath={`url(#${clipId})`}>
        {/* Base dark circle */}
        <circle cx={cx} cy={cy} r={r} fill={bgColor} />

        {/* Lit portion */}
        <path d={litPath} fill={fgColor} />
      </g>
    </svg>
  );
};

