import React from 'react';

interface MoonPhaseIconProps {
  phase: number; // 0 (new) to 1 (new)
  isNightMode: boolean;
}

export const MoonPhaseIcon: React.FC<MoonPhaseIconProps> = ({ phase, isNightMode }) => {
  const size = 64;
  const r = size / 2 - 2;
  const cx = size / 2;
  const cy = size / 2;
  const clipId = `moon-clip-${Math.random()}`;

  const fgColor = isNightMode ? '#fca5a5' : '#e5e7eb'; // red-300 or gray-200
  const bgColor = isNightMode ? 'rgba(127, 29, 29, 0.5)' : '#374151'; // red-900/50 or gray-700

  const angle = phase * 2 * Math.PI;
  const terminatorRx = Math.abs(r * Math.cos(angle));

  // Path for the lit part
  let litPath;
  if (phase <= 0.01 || phase >= 0.99) { // New Moon
    litPath = '';
  } else if (phase > 0.49 && phase < 0.51) { // Full Moon
    litPath = `M${cx - r},${cy} a${r},${r} 0 1,0 ${2 * r},0 a${r},${r} 0 1,0 -${2 * r},0`;
  } else if (phase < 0.5) { // Waxing (light on the right)
    litPath = `
      M${cx},${cy - r}
      A${r},${r} 0 0,0 ${cx},${cy + r}
      A${terminatorRx},${r} 0 0,1 ${cx},${cy - r}
    `;
  } else { // Waning (light on the left)
    litPath = `
      M${cx},${cy - r}
      A${r},${r} 0 0,1 ${cx},${cy + r}
      A${terminatorRx},${r} 0 0,0 ${cx},${cy - r}
    `;
  }

  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      <defs>
        <clipPath id={clipId}>
          <circle cx={cx} cy={cy} r={r} />
        </clipPath>
      </defs>

      <g clipPath={`url(#${clipId})`}>
        {/* Base dark circle */}
        <circle cx={cx} cy={cy} r={r} fill={bgColor} />

        {/* Lit portion */}
        <path d={litPath} fill={fgColor} />
      </g>
    </svg>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { useGeolocation } from '../hooks/useGeolocation';
import { AstroObject, LocationData } from '../types';

interface ObjectCatalogProps {
  isNightMode: boolean;
}

const catalogs = [
    { id: 'Messier', name: 'Messier', path: '/data/messier.json', paginated: false, totalPages: 1 },
    { id: 'Caldwell', name: 'Caldwell', path: '/data/caldwell.json', paginated: false, totalPages: 1 },
    { id: 'Melotte', name: 'Melotte', path: '/data/melotte.json', paginated: false, totalPages: 1 },
    { id: 'NGC', name: 'NGC', path: '/data/ngc/ngc_{page}.json', paginated: true, totalPages: 157 }
];

const useSkyPositionCalculator = (objects: AstroObject[], location: LocationData | null) => {
    const [positions, setPositions] = useState<{[key: string]: {alt: number | null}}>({});

    useEffect(() => {
        if (!location || objects.length === 0) {
            setPositions({});
            return;
        }

        const DEGREES_TO_RADIANS = Math.PI / 180;
        const RADIANS_TO_DEGREES = 180 / Math.PI;

        const calculatePositions = () => {
            const now = new Date();
            const j2000 = new Date(Date.UTC(2000, 0, 1, 12, 0, 0));
            const diff = now.getTime() - j2000.getTime();
            const d = diff / (1000 * 60 * 60 * 24);
            const ut = now.getUTCHours() + now.getUTCMinutes() / 60 + now.getUTCSeconds() / 3600;
            const gmst = 18.697374558 + 24.06570982441908 * d;
            const lst_hours = (gmst + ut + location.longitude / 15) % 24;
            const lst_degrees = (lst_hours < 0 ? lst_hours + 24 : lst_hours) * 15;

            const newPositions: {[key: string]: {alt: number | null}} = {};

            objects.forEach(obj => {
                let ha_degrees = lst_degrees - (obj.ra * 15);
                if (ha_degrees < 0) ha_degrees += 360;

                const lat_rad = location.latitude * DEGREES_TO_RADIANS;
                const dec_rad = obj.dec * DEGREES_TO_RADIANS;
                const ha_rad = ha_degrees * DEGREES_TO_RADIANS;

                const sin_alt = Math.sin(dec_rad) * Math.sin(lat_rad) + Math.cos(dec_rad) * Math.cos(lat_rad) * Math.cos(ha_rad);
                const alt_rad = Math.asin(sin_alt);
                newPositions[obj.id] = { alt: alt_rad * RADIANS_TO_DEGREES };
            });
            setPositions(newPositions);
        };

        calculatePositions();
        const interval = setInterval(calculatePositions, 60000); // Recalculate every minute
        return () => clearInterval(interval);

    }, [objects, location]);

    return positions;
};


export const ObjectCatalog: React.FC<ObjectCatalogProps> = ({ isNightMode }) => {
  const { location } = useGeolocation();
  const [searchTerm, setSearchTerm] = useState('');
  const [showVisibleOnly, setShowVisibleOnly] = useState(false);
  const [objects, setObjects] = useState<AstroObject[]>([]);
  const [loading, setLoading] = useState(false);
  const [selectedCatalog, setSelectedCatalog] = useState(catalogs[0]);
  const [currentPage, setCurrentPage] = useState(1);

  useEffect(() => {
    const fetchObjects = async () => {
        setLoading(true);
        const path = selectedCatalog.path.replace('{page}', String(currentPage));
        try {
            const response = await fetch(path);
            if (!response.ok) throw new Error('Network response was not ok');
            const data: AstroObject[] = await response.json();
            setObjects(data);
        } catch (error) {
            console.error("Failed to fetch catalog data:", error);
            setObjects([]);
        } finally {
            setLoading(false);
        }
    };
    fetchObjects();
  }, [selectedCatalog, currentPage]);

  const positions = useSkyPositionCalculator(objects, location);

  const filteredObjects = useMemo(() => {
    let results = objects.map(obj => ({
        ...obj,
        alt: positions[obj.id]?.alt ?? null
    }));

    if (searchTerm) {
      results = results.filter(obj => 
        obj.id.toLowerCase().includes(searchTerm.toLowerCase()) || 
        (obj.name && obj.name.toLowerCase().includes(searchTerm.toLowerCase()))
      );
    }

    if (showVisibleOnly) {
        results = results.filter(obj => obj.alt !== null && obj.alt > 0);
    }

    return results.sort((a, b) => (b.alt ?? -999) - (a.alt ?? -999));
  }, [searchTerm, showVisibleOnly, objects, positions]);

  const handleCatalogChange = (catalogId: string) => {
    const newCatalog = catalogs.find(c => c.id === catalogId);
    if(newCatalog) {
        setSelectedCatalog(newCatalog);
        setCurrentPage(1);
    }
  };

  const cardBg = isNightMode ? 'bg-red-900/20 border-red-800/50' : 'bg-gray-800/50 border-gray-700';
  const inputStyle = "p-2 rounded-md bg-gray-700 border-gray-600 text-white";

  return (
    <div className="animate-fade-in">
      <h2 className={`text-3xl font-bold mb-6 ${isNightMode ? 'text-red-400' : 'text-white'}`}>Objektum Katalógus</h2>
      <div className={`p-4 rounded-lg border ${cardBg} mb-6 flex flex-col sm:flex-row gap-4 items-center`}>
        <select value={selectedCatalog.id} onChange={e => handleCatalogChange(e.target.value)} className={`${inputStyle} sm:w-40`}>
            {catalogs.map(cat => <option key={cat.id} value={cat.id}>{cat.name}</option>)}
        </select>
        <input 
          type="text" 
          placeholder={`Keresés a ${selectedCatalog.name} katalógusban...`}
          value={searchTerm} 
          onChange={e => setSearchTerm(e.target.value)} 
          className={`${inputStyle} flex-grow`}
        />
        <label className="flex items-center space-x-2 cursor-pointer text-sm">
            <input type="checkbox" checked={showVisibleOnly} onChange={() => setShowVisibleOnly(!showVisibleOnly)} className="form-checkbox h-5 w-5 bg-gray-700 border-gray-600 rounded"/>
            <span>Csak látható</span>
        </label>
      </div>

      {selectedCatalog.paginated && (
        <div className="flex justify-center items-center gap-4 mb-4">
            <button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="px-4 py-2 rounded disabled:opacity-50">‹ Előző</button>
            <span className="text-sm">Oldal {currentPage} / {selectedCatalog.totalPages}</span>
            <button onClick={() => setCurrentPage(p => Math.min(selectedCatalog.totalPages, p + 1))} disabled={currentPage === selectedCatalog.totalPages} className="px-4 py-2 rounded disabled:opacity-50">Következő ›</button>
        </div>
      )}

      <div className="overflow-x-auto">
        <table className="w-full text-sm text-left">
          <thead className={`${isNightMode ? 'text-red-300' : 'text-gray-300'}`}>
            <tr>
              <th className="p-2">ID</th><th className="p-2">Név</th><th className="p-2">Típus</th>
              <th className="p-2">Csillagkép</th><th className="p-2 text-center">Mag.</th><th className="p-2 text-center">Magasság</th>
            </tr>
          </thead>
          <tbody>
            {loading ? (
                <tr><td colSpan={6} className="text-center p-4">Betöltés...</td></tr>
            ) : filteredObjects.map(obj => (
                <ObjectRow key={obj.id} obj={obj} isNightMode={isNightMode} />
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

const ObjectRow = React.memo(({ obj, isNightMode }: { obj: AstroObject & {alt: number | null}; isNightMode: boolean; }) => {
    const { alt } = obj;
    return (
        <tr className={`border-t ${isNightMode ? 'border-red-800/50' : 'border-gray-700'} ${alt !== null && alt < 0 ? 'opacity-40' : ''}`}>
            <td className="p-2 font-bold">{obj.id}</td><td className="p-2">{obj.name}</td>
            <td className="p-2">{obj.type}</td><td className="p-2">{obj.constellation}</td>
            <td className="p-2 text-center">{obj.magnitude}</td>
            <td className={`p-2 text-center font-medium ${alt === null ? '' : alt > 10 ? (isNightMode ? 'text-green-400' : 'text-green-500') : alt > 0 ? 'text-yellow-500' : (isNightMode ? 'text-red-600': 'text-gray-500')}`}>
                {alt === null ? '...' : `${alt.toFixed(1)}°`}
            </td>
        </tr>
    );
});

