import React, { useState, useMemo } from 'react';
import { LocationData } from '../types';

declare const SunCalc: any;

interface AnalemmaProps {
    location: LocationData;
    isNightMode: boolean;
}

const RADIANS_TO_DEGREES = 180 / Math.PI;

export const Analemma: React.FC<AnalemmaProps> = ({ location, isNightMode }) => {
    const [timeOfDay, setTimeOfDay] = useState(12); // Hour of the day (0-23)
    const [timeMode, setTimeMode] = useState<'UTC' | 'Local'>('UTC');

    const analemmaData = useMemo(() => {
        const points = [];
        const year = new Date().getFullYear();
        let specialPoints = {
            marEq: { alt: 0, az: 0 },
            junSol: { alt: 0, az: 0 },
            sepEq: { alt: 0, az: 0 },
            decSol: { alt: 0, az: 0 },
            today: { alt: 0, az: 0 },
        };

        for (let i = 0; i < 365; i++) {
            const date = new Date(year, 0, i + 1);
            if (timeMode === 'UTC') {
                date.setUTCHours(timeOfDay, 0, 0, 0);
            } else {
                date.setHours(timeOfDay, 0, 0, 0);
            }

            const sunPos = SunCalc.getPosition(date, location.latitude, location.longitude);
            const point = {
                alt: sunPos.altitude * RADIANS_TO_DEGREES,
                az: (sunPos.azimuth * RADIANS_TO_DEGREES + 180) % 360, // Azimuth 0 at South
            };
            points.push(point);

            // Find special points (approximate)
            if (i === 79) specialPoints.marEq = point; // March 20
            if (i === 172) specialPoints.junSol = point; // June 21
            if (i === 265) specialPoints.sepEq = point; // Sep 22
            if (i === 355) specialPoints.decSol = point; // Dec 21
        }

        // Today's point
        const today = new Date();
        if (timeMode === 'UTC') {
            today.setUTCHours(timeOfDay, 0, 0, 0);
        } else {
            today.setHours(timeOfDay, 0, 0, 0);
        }
        const todaySunPos = SunCalc.getPosition(today, location.latitude, location.longitude);
        specialPoints.today = {
            alt: todaySunPos.altitude * RADIANS_TO_DEGREES,
            az: (todaySunPos.azimuth * RADIANS_TO_DEGREES + 180) % 360,
        };

        return { points, specialPoints };
    }, [location, timeOfDay, timeMode]);

    const width = 500;
    const height = 250;
    const padding = 30;

    const toSvgCoords = (az: number, alt: number) => {
        const x = ((az - 90) / 180) * (width - 2 * padding) + padding; // Azimuth from 90 (East) to 270 (West)
        const y = height - padding - (alt / 90) * (height - 2 * padding);
        return { x, y };
    };

    const pathData = analemmaData.points
        .filter(p => p.alt > 0)
        .map(p => {
            const { x, y } = toSvgCoords(p.az, p.alt);
            return `${x},${y}`;
        })
        .join(' L ');

    const textColor = isNightMode ? "text-red-400" : "text-gray-400";

    return (
        <div>
            <div className="flex items-center justify-center gap-4 mb-2">
                 <label className="flex items-center cursor-pointer">
                    <input type="checkbox" checked={timeMode === 'Local'} onChange={() => setTimeMode(timeMode === 'UTC' ? 'Local' : 'UTC')} className="sr-only peer" />
                    <div className="relative w-11 h-6 bg-gray-600 rounded-full peer peer-checked:after:translate-x-full rtl:peer-checked:after:-translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-0.5 after:start-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-blue-600"></div>
                    <span className="ms-3 text-sm font-medium">{timeMode}</span>
                </label>
                <input
                    type="range"
                    min="0"
                    max="23"
                    value={timeOfDay}
                    onChange={(e) => setTimeOfDay(parseInt(e.target.value))}
                    className="w-full md:w-1/2"
                />
                <span className="text-sm font-mono w-16 text-center">{String(timeOfDay).padStart(2, '0')}:00</span>
            </div>

            <svg viewBox={`0 0 ${width} ${height}`} className="w-full">
                {/* Grid */}
                {[...Array(4)].map((_, i) => (
                    <line key={`h-${i}`} x1={padding} x2={width-padding} y1={height - padding - (i*22.5/90)*(height-2*padding)} stroke={isNightMode ? '#5a2222' : '#e0e0e0'} strokeWidth="0.5" />
                ))}
                 {[...Array(5)].map((_, i) => (
                    <line key={`v-${i}`} y1={padding} y2={height-padding} x1={padding + (i*45/180)*(width-2*padding)} stroke={isNightMode ? '#5a2222' : '#e0e0e0'} strokeWidth="0.5" />
                ))}

                {/* Path */}
                {pathData && <path d={`M ${pathData}`} stroke={isNightMode ? "orange" : "blue"} strokeWidth="1" fill="none" />}

                {/* Special Points */}
                {Object.entries(analemmaData.specialPoints).map(([key, p]) => {
                    if (p.alt < 0) return null;
                    const {x, y} = toSvgCoords(p.az, p.alt);
                    const color = key === 'today' ? (isNightMode ? 'yellow' : 'red') : (isNightMode ? 'cyan' : 'green');
                    return <circle key={key} cx={x} cy={y} r={key === 'today' ? 3 : 2} fill={color} />;
                })}

                {/* Labels */}
                <text x={width/2} y={height-5} textAnchor="middle" fontSize="10" fill={isNightMode ? 'red' : 'black'}>D</text>
                <text x={padding-5} y={height-padding} textAnchor="end" fontSize="10" fill={isNightMode ? 'red' : 'black'}>K</text>
                <text x={width-padding+5} y={height-padding} textAnchor="start" fontSize="10" fill={isNightMode ? 'red' : 'black'}>Ny</text>
                 {[...Array(5)].map((_, i) => (
                   <text key={`l-${i}`} x={padding + (i*45/180)*(width-2*padding)} y={height-padding+12} textAnchor="middle" fontSize="8" fill={isNightMode ? 'red' : 'black'}>{90+i*45}°</text>
                ))}
            </svg>
            <div className={`text-xs flex justify-center gap-4 mt-1 ${textColor}`}>
                <span><span className="text-cyan-400">●</span> Napforduló/Napéjegyenlőség</span>
                <span><span className="text-yellow-400">●</span> Mai pozíció</span>
            </div>
        </div>
    );
};

