const DataRow = ({ label, value, isNightMode }: { label: string; value: string | React.ReactNode; isNightMode: boolean }) => (
    <div className="flex justify-between items-center py-2 border-b border-opacity-50 last:border-b-0">
        <span className={`text-sm ${isNightMode ? 'text-red-400' : 'text-gray-400'}`}>{label}</span>
        <span className={`text-sm font-medium text-right ${isNightMode ? 'text-red-300' : 'text-white'}`}>{value}</span>
    </div>
);

const formatTime = (date: Date | null) => date ? date.toLocaleTimeString('hu-HU', { hour: '2-digit', minute: '2-digit' }) : 'N/A';
const formatDate = (date: Date | null) => date ? date.toLocaleDateString('hu-HU', { month: '2-digit', day: '2-digit' }) : 'N/A';
const formatNumber = (num: number) => num.toLocaleString('hu-HU', { maximumFractionDigits: 0 });

const getMoonPhaseName = (phase: number) => {
    if (phase < 0.03 || phase > 0.97) return 'Újhold';
    if (phase < 0.22) return 'Növő sarló';
    if (phase < 0.28) return 'Első negyed';
    if (phase < 0.47) return 'Növő hold';
    if (phase < 0.53) return 'Telihold';
    if (phase < 0.72) return 'Fogyó hold';
    if (phase < 0.78) return 'Utolsó negyed';
    return 'Fogyó sarló';
};

// Countdown component
const Countdown = ({ toDate }: { toDate: Date }) => {
    const [timeLeft, setTimeLeft] = useState('');

    useEffect(() => {
        const calculateTimeLeft = () => {
            const diff = toDate.getTime() - new Date().getTime();
            if (diff < 0) {
                setTimeLeft('Most');
                return;
            }
            const days = Math.floor(diff / (1000 * 60 * 60 * 24));
            const hours = Math.floor((diff / (1000 * 60 * 60)) % 24);
            const minutes = Math.floor((diff / 1000 / 60) % 60);
            setTimeLeft(`(${days}n ${hours}ó ${minutes}p)`);
        };

        calculateTimeLeft();
        const timer = setInterval(calculateTimeLeft, 60000); // update every minute
        return () => clearInterval(timer);
    }, [toDate]);

    return <span className="ml-2">{timeLeft}</span>;
};


export const Dashboard: React.FC<DashboardProps> = ({ isNightMode }) => {
  const { location, error: geoError, loading: geoLoading } = useGeolocation();
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const sunData = useMemo(() => {
    if (!location) return null;
    return SunCalc.getTimes(new Date(), location.latitude, location.longitude);
  }, [location, time.getDate()]);

  const moonData = useMemo(() => {
    if (!location) return null;
    const now = new Date();
    const moonIllumination = SunCalc.getMoonIllumination(now);
    const moonTimes = SunCalc.getMoonTimes(now, location.latitude, location.longitude);
    const moonPosition = SunCalc.getMoonPosition(now, location.latitude, location.longitude);

    let date = new Date();
    let phases = [];
    let nextNew = null, nextFirst = null, nextFull = null, nextLast = null;

    for(let i=0; i < 35 * 24; i++) {
        date.setHours(date.getHours() + 1);
        const p = SunCalc.getMoonIllumination(date).phase;
        if(i > 0) {
            const prev_p = SunCalc.getMoonIllumination(new Date(date.getTime() - 3600000)).phase;
            if(!nextNew && prev_p > 0.9 && p < 0.1) { nextNew = new Date(date); phases.push({name: "Újhold", date: nextNew}); }
            if(!nextFirst && prev_p < 0.25 && p > 0.25) { nextFirst = new Date(date); phases.push({name: "Első negyed", date: nextFirst}); }
            if(!nextFull && prev_p < 0.5 && p > 0.5) { nextFull = new Date(date); phases.push({name: "Telihold", date: nextFull}); }
            if(!nextLast && prev_p < 0.75 && p > 0.75) { nextLast = new Date(date); phases.push({name: "Utolsó negyed", date: nextLast}); }
        }
        if(nextNew && nextFirst && nextFull && nextLast) break;
    }

    phases.sort((a, b) => a.date.getTime() - b.date.getTime());

    return { ...moonIllumination, ...moonTimes, ...moonPosition, nextPhases: phases };
  }, [location, time.getDate()]);

  const planets = useMemo(() => {
      // NOTE: Accurate real-time planet positions require a dedicated astronomical library.
      // The 'isUp' status and constellation are approximations for mid-2024 for demonstration purposes.
      const now = new Date();
      // A very rough estimation of visibility based on time of day
      const isNight = now.getHours() > 19 || now.getHours() < 5;

      const planetsData = [
          { name: 'Merkúr', constellation: 'Változó', isUp: false }, // Changes too fast for a static app
          { name: 'Vénusz', constellation: 'Ikrek', isUp: false }, // Changes position frequently
          { name: 'Mars', constellation: 'Halak', isUp: isNight },
          { name: 'Jupiter', constellation: 'Bika', isUp: isNight },
          { name: 'Szaturnusz', constellation: 'Vízöntő', isUp: isNight },
          { name: 'Uránusz', constellation: 'Bika', isUp: isNight },
          { name: 'Neptunusz', constellation: 'Halak', isUp: isNight },
      ];
      return planetsData;
  }, [time.getHours()]);

  const getJulianDate = (date: Date) => {
    return (date.getTime() / 86400000) + 2440587.5;
  };

  const formatCoordinate = (coord: number, type: 'lat' | 'lon') => {
    const direction = coord >= 0 ? (type === 'lat' ? 'É' : 'K') : (type === 'lat' ? 'D' : 'Ny');
    return `${Math.abs(coord).toFixed(4)}° ${direction}`;
  };

  const cardBg = isNightMode ? 'bg-red-900/20 border-red-800/50' : 'bg-gray-800/50 border-gray-700';
  const headingColor = isNightMode ? 'text-red-400' : 'text-white';
  const subHeadingColor = `text-xl font-semibold mb-3 pb-2 ${isNightMode ? 'border-red-800 text-red-400' : 'border-gray-600 text-white'}`;

  return (
    <div className="animate-fade-in">
      <h2 className={`text-3xl font-bold mb-6 ${headingColor}`}>Helyi Égbolt Adatok</h2>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6">
        {/* Sun Card */}
        <div className={`p-4 sm:p-6 rounded-lg border ${cardBg}`}>
            <h3 className={subHeadingColor}>Nap</h3>
            {geoLoading ? <p>Pozíció meghatározása...</p> : location && sunData ? (
                 <div className="text-sm">
                    <DataRow isNightMode={isNightMode} label="Napkelte" value={formatTime(sunData.sunrise)} />
                    <DataRow isNightMode={isNightMode} label="Kulmináció" value={formatTime(sunData.solarNoon)} />
                    <DataRow isNightMode={isNightMode} label="Napnyugta" value={formatTime(sunData.sunset)} />
                    <DataRow isNightMode={isNightMode} label="Polgári szürkület" value={`${formatTime(sunData.dawn)} - ${formatTime(sunData.dusk)}`} />
                    <DataRow isNightMode={isNightMode} label="Csillagászati szürkület" value={`${formatTime(sunData.astronomicalDawn)} - ${formatTime(sunData.astronomicalDusk)}`} />
                 </div>
            ) : <p>{geoError || "Adatok betöltése..."}</p>}
        </div>
        {/* Moon Card */}
        <div className={`p-4 sm:p-6 rounded-lg border ${cardBg}`}>
            <h3 className={subHeadingColor}>Hold</h3>
             {geoLoading ? <p>Pozíció meghatározása...</p> : location && moonData ? (
                <div>
                    <div className="flex space-x-4 mb-4">
                        <div className="flex-shrink-0">
                            <MoonPhaseIcon phase={moonData.phase} isNightMode={isNightMode} />
                        </div>
                        <div className="flex-grow text-sm">
                            <DataRow isNightMode={isNightMode} label="Fázis" value={getMoonPhaseName(moonData.phase)} />
                            <DataRow isNightMode={isNightMode} label="Megvilágítás" value={`${(moonData.fraction * 100).toFixed(1)}%`} />
                             <DataRow isNightMode={isNightMode} label="Távolság" value={`${formatNumber(moonData.distance)} km`} />
                            <DataRow isNightMode={isNightMode} label="Holdkelte" value={formatTime(moonData.rise)} />
                            <DataRow isNightMode={isNightMode} label="Holdnyugta" value={formatTime(moonData.set)} />
                        </div>
                    </div>
                    <div className="text-xs">
                         {moonData.nextPhases.slice(0, 4).map(phase => (
                            <DataRow 
                                key={phase.name} 
                                isNightMode={isNightMode} 
                                label={`Következő ${phase.name.toLowerCase()}`} 
                                value={
                                    <span className="flex items-center justify-end">
                                        {formatDate(phase.date)}
                                        <Countdown toDate={phase.date} />
                                    </span>
                                }
                            />
                        ))}
                    </div>
                </div>
            ) : <p>{geoError || "Adatok betöltése..."}</p>}
        </div>
        {/* Planets Card */}
        <div className={`p-4 sm:p-6 rounded-lg border ${cardBg}`}>
            <h3 className={subHeadingColor}>Bolygók</h3>
             {geoLoading ? <p>Pozíció meghatározása...</p> : location ? (
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 text-center">
                    {planets.map(p => (
                        <div key={p.name}>
                            <p className={`font-semibold ${isNightMode ? 'text-red-300' : 'text-white'}`}>{p.name}</p>
                            <p className={`text-xs ${isNightMode ? 'text-red-400' : 'text-gray-400'}`}>{p.constellation}</p>
                            <p className={`text-sm ${p.isUp ? 'text-green-400' : isNightMode ? 'text-red-500' : 'text-gray-500'}`}>
                                {p.isUp ? 'Látható' : 'Horizont alatt'}
                            </p>
                        </div>
                    ))}
                </div>
            ) : <p>{geoError || "Adatok betöltése..."}</p>}
             <p className={`text-xs text-center mt-3 ${isNightMode ? 'text-red-700' : 'text-gray-500'}`}>(A bolygók láthatósága és pozíciója egyszerűsített becslés)</p>
        </div>
        {/* Analemma Card */}
        {location && (
            <div className={`p-4 sm:p-6 rounded-lg border ${cardBg}`}>
                 <h3 className={subHeadingColor}>Napi Nap-út (Analemma)</h3>
                 <Analemma location={location} isNightMode={isNightMode} />
            </div>
        )}
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        <InfoCard title="Helyi Idő" value={time.toLocaleTimeString()} icon={<ClockIcon className="w-6 h-6"/>} isNightMode={isNightMode} />
        <InfoCard title="UTC" value={time.toUTCString().split(' ')[4]} icon={<GlobeIcon className="w-6 h-6"/>} isNightMode={isNightMode} />
        <InfoCard title="Julián Dátum" value={getJulianDate(time).toFixed(5)} icon={<CalendarIcon className="w-6 h-6"/>} isNightMode={isNightMode} />
        <InfoCard title="Szélesség" value={location ? formatCoordinate(location.latitude, 'lat') : (geoError || '...')} icon={<CompassIcon className="w-6 h-6"/>} isNightMode={isNightMode} loading={geoLoading} />
        <InfoCard title="Hosszúság" value={location ? formatCoordinate(location.longitude, 'lon') : (geoError || '...')} icon={<CompassIcon className="w-6 h-6"/>} isNightMode={isNightMode} loading={geoLoading} />
      </div>
       {geoError && (
        <div className={`mt-6 p-4 rounded-lg text-sm ${isNightMode ? 'bg-red-900/30 text-red-300 border border-red-800' : 'bg-yellow-900/30 text-yellow-300 border border-yellow-800'}`}>
          <strong>Helymeghatározási Hiba:</strong> {geoError}. Kérjük, engedélyezze a helymeghatározást a böngészőben.
        </div>
      )}
    </div>
  );
};

import React from 'react';

interface MoonPhaseIconProps {
  phase: number; // 0 (new) to 1 (new)
  isNightMode: boolean;
}

export const MoonPhaseIcon: React.FC<MoonPhaseIconProps> = ({ phase, isNightMode }) => {
  const size = 80;
  const r = size / 2 - 4; // larger radius, more padding
  const cx = size / 2;
  const cy = size / 2;
  const glowId = `glow-${Math.random()}`;

  const fgColor = isNightMode ? '#fca5a5' : '#e5e7eb'; // red-300 or gray-200
  const bgColor = isNightMode ? 'rgba(42, 16, 16, 0.9)' : '#1f2937'; // A darker red, distinct from black

  const angle = phase * 2 * Math.PI;
  const terminatorRx = Math.abs(r * Math.cos(angle));

  // Path for the shadow part
  let shadowPath;
  if (phase <= 0.01 || phase >= 0.99) { // New Moon
    shadowPath = `M${cx-r},${cy} a${r},${r} 0 1,0 ${2*r},0 a${r},${r} 0 1,0 -${2*r},0`;
  } else if (phase > 0.49 && phase < 0.51) { // Full Moon
    shadowPath = '';
  } else if (phase < 0.5) { // Waxing: shadow is on the left
    shadowPath = `
      M${cx},${cy - r}
      A${r},${r} 0 0,0 ${cx},${cy + r}
      A${terminatorRx},${r} 0 0,1 ${cx},${cy - r}
    `;
  } else { // Waning: shadow is on the right
    shadowPath = `
      M${cx},${cy - r}
      A${r},${r} 0 0,1 ${cx},${cy + r}
      A${terminatorRx},${r} 0 0,0 ${cx},${cy - r}
    `;
  }

  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      <defs>
        <filter id={glowId} x="-50%" y="-50%" width="200%" height="200%">
          <feGaussianBlur stdDeviation="2.5" result="coloredBlur" />
          <feMerge>
            <feMergeNode in="coloredBlur" />
            <feMergeNode in="SourceGraphic" />
          </feMerge>
        </filter>
      </defs>

      <g filter={`url(#${glowId})`}>
        {/* Base lit circle */}
        <circle cx={cx} cy={cy} r={r} fill={fgColor} />
        {/* Shadow portion */}
        <path d={shadowPath} fill={bgColor} />
      </g>
    </svg>
  );
};

import React, { useState, useMemo } from 'react';
import { LocationData } from '../types';

declare const SunCalc: any;

interface AnalemmaProps {
    location: LocationData;
    isNightMode: boolean;
}

const RADIANS_TO_DEGREES = 180 / Math.PI;

export const Analemma: React.FC<AnalemmaProps> = ({ location, isNightMode }) => {
    const [timeOfDay, setTimeOfDay] = useState(12); // Hour of the day (0-23)
    const [timeMode, setTimeMode] = useState<'UTC' | 'Local'>('UTC');

    const analemmaData = useMemo(() => {
        const points = [];
        const year = new Date().getFullYear();
        let specialPoints = {
            marEq: { alt: 0, az: 0 },
            junSol: { alt: 0, az: 0 },
            sepEq: { alt: 0, az: 0 },
            decSol: { alt: 0, az: 0 },
            today: { alt: 0, az: 0 },
        };

        for (let i = 0; i < 365; i++) {
            const date = new Date(year, 0, i + 1);
            if (timeMode === 'UTC') {
                date.setUTCHours(timeOfDay, 0, 0, 0);
            } else {
                date.setHours(timeOfDay, 0, 0, 0);
            }

            const sunPos = SunCalc.getPosition(date, location.latitude, location.longitude);
            const point = {
                alt: sunPos.altitude * RADIANS_TO_DEGREES,
                az: (sunPos.azimuth * RADIANS_TO_DEGREES + 180) % 360, // Azimuth 0 at South
            };
            points.push(point);

            // Find special points (approximate)
            if (i === 79) specialPoints.marEq = point; // March 20
            if (i === 172) specialPoints.junSol = point; // June 21
            if (i === 265) specialPoints.sepEq = point; // Sep 22
            if (i === 355) specialPoints.decSol = point; // Dec 21
        }

        // Today's point
        const today = new Date();
        if (timeMode === 'UTC') {
            today.setUTCHours(timeOfDay, 0, 0, 0);
        } else {
            today.setHours(timeOfDay, 0, 0, 0);
        }
        const todaySunPos = SunCalc.getPosition(today, location.latitude, location.longitude);
        specialPoints.today = {
            alt: todaySunPos.altitude * RADIANS_TO_DEGREES,
            az: (todaySunPos.azimuth * RADIANS_TO_DEGREES + 180) % 360,
        };

        return { points, specialPoints };
    }, [location, timeOfDay, timeMode]);

    const width = 500;
    const height = 250;
    const padding = 20;

    const toSvgCoords = (az: number, alt: number) => {
        const x = ((az - 90) / 180) * (width - 2 * padding) + padding; // Azimuth from 90 (East) to 270 (West)
        const y = height - padding - (alt / 90) * (height - 2 * padding);
        return { x, y };
    };

    const pathData = analemmaData.points
        .filter(p => p.alt > 0)
        .map(p => {
            const { x, y } = toSvgCoords(p.az, p.alt);
            return `${x},${y}`;
        })
        .join(' L ');

    const textColor = isNightMode ? "text-red-400" : "text-gray-400";

    return (
        <div>
            <div className="flex items-center justify-center gap-4 mb-2">
                 <label className="flex items-center cursor-pointer">
                    <input type="checkbox" checked={timeMode === 'Local'} onChange={() => setTimeMode(timeMode === 'UTC' ? 'Local' : 'UTC')} className="sr-only peer" />
                    <div className="relative w-11 h-6 bg-gray-600 rounded-full peer peer-checked:after:translate-x-full rtl:peer-checked:after:-translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-0.5 after:start-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-blue-600"></div>
                    <span className="ms-3 text-sm font-medium">{timeMode}</span>
                </label>
                <input
                    type="range"
                    min="0"
                    max="23"
                    value={timeOfDay}
                    onChange={(e) => setTimeOfDay(parseInt(e.target.value))}
                    className="w-full md:w-1/2"
                />
                <span className="text-sm font-mono w-16 text-center">{String(timeOfDay).padStart(2, '0')}:00</span>
            </div>

            <svg viewBox={`0 0 ${width} ${height}`} className="w-full">
                {/* Path */}
                {pathData && <path d={`M ${pathData}`} stroke={isNightMode ? "orange" : "blue"} strokeWidth="1" fill="none" />}

                {/* Special Points */}
                {Object.entries(analemmaData.specialPoints).map(([key, p]) => {
                    if (p.alt < 0) return null;
                    const {x, y} = toSvgCoords(p.az, p.alt);
                    const color = key === 'today' ? (isNightMode ? 'yellow' : 'red') : (isNightMode ? 'cyan' : 'green');
                    return <circle key={key} cx={x} cy={y} r={key === 'today' ? 3 : 2} fill={color} />;
                })}

                {/* Labels */}
                <text x={width/2} y={height-5} textAnchor="middle" fontSize="10" fill={isNightMode ? 'red' : 'black'}>D</text>
                <text x={padding-5} y={height-padding} textAnchor="end" fontSize="10" fill={isNightMode ? 'red' : 'black'}>K</text>
                <text x={width-padding+5} y={height-padding} textAnchor="start" fontSize="10" fill={isNightMode ? 'red' : 'black'}>Ny</text>
                 {[...Array(5)].map((_, i) => (
                   <text key={`l-${i}`} x={padding + (i*45/180)*(width-2*padding)} y={height-padding+12} textAnchor="middle" fontSize="8" fill={isNightMode ? 'red' : 'black'}>{90+i*45}°</text>
                ))}
            </svg>
            <div className={`text-xs flex justify-center gap-4 mt-1 ${textColor}`}>
