import React, { useState, useMemo } from 'react';
import { LocationData } from '../types';

declare const SunCalc: any;

interface AnalemmaProps {
    location: LocationData;
    isNightMode: boolean;
}

const RADIANS_TO_DEGREES = 180 / Math.PI;

export const Analemma: React.FC<AnalemmaProps> = ({ location, isNightMode }) => {
    const [timeOfDay, setTimeOfDay] = useState(12); // Hour of the day (0-23)
    const [timeMode, setTimeMode] = useState<'UTC' | 'Local'>('UTC');

    const analemmaData = useMemo(() => {
        const points = [];
        const year = new Date().getFullYear();
        let specialPoints = {
            marEq: { alt: 0, az: 0 },
            junSol: { alt: 0, az: 0 },
            sepEq: { alt: 0, az: 0 },
            decSol: { alt: 0, az: 0 },
            today: { alt: 0, az: 0 },
        };

        for (let i = 0; i < 365; i++) {
            const date = new Date(year, 0, i + 1);
            if (timeMode === 'UTC') {
                date.setUTCHours(timeOfDay, 0, 0, 0);
            } else {
                date.setHours(timeOfDay, 0, 0, 0);
            }

            const sunPos = SunCalc.getPosition(date, location.latitude, location.longitude);
            const point = {
                alt: sunPos.altitude * RADIANS_TO_DEGREES,
                az: (sunPos.azimuth * RADIANS_TO_DEGREES + 180) % 360, // Azimuth 0 at South
            };
            points.push(point);

            // Find special points (approximate)
            if (i === 79) specialPoints.marEq = point; // March 20
            if (i === 172) specialPoints.junSol = point; // June 21
            if (i === 265) specialPoints.sepEq = point; // Sep 22
            if (i === 355) specialPoints.decSol = point; // Dec 21
        }

        // Today's point
        const today = new Date();
        if (timeMode === 'UTC') {
            today.setUTCHours(timeOfDay, 0, 0, 0);
        } else {
            today.setHours(timeOfDay, 0, 0, 0);
        }
        const todaySunPos = SunCalc.getPosition(today, location.latitude, location.longitude);
        specialPoints.today = {
            alt: todaySunPos.altitude * RADIANS_TO_DEGREES,
            az: (todaySunPos.azimuth * RADIANS_TO_DEGREES + 180) % 360,
        };

        return { points, specialPoints };
    }, [location, timeOfDay, timeMode]);

    const width = 500;
    const height = 350;
    const padding = 20;

    const toSvgCoords = (az: number, alt: number) => {
        const x = ((az - 90) / 180) * (width - 2 * padding) + padding; // Azimuth from 90 (East) to 270 (West)
        const y = height - padding - (alt / 90) * (height - 2 * padding);
        return { x, y };
    };

    const pathData = analemmaData.points
        .filter(p => p.alt > 0)
        .map(p => {
            const { x, y } = toSvgCoords(p.az, p.alt);
            return `${x},${y}`;
        })
        .join(' L ');

    const textColor = isNightMode ? "text-red-400" : "text-gray-400";

    return (
        <div>
            <div className="flex items-center justify-center gap-4 mb-2">
                 <label className="flex items-center cursor-pointer">
                    <input type="checkbox" checked={timeMode === 'Local'} onChange={() => setTimeMode(timeMode === 'UTC' ? 'Local' : 'UTC')} className="sr-only peer" />
                    <div className="relative w-11 h-6 bg-gray-600 rounded-full peer peer-checked:after:translate-x-full rtl:peer-checked:after:-translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-0.5 after:start-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-blue-600"></div>
                    <span className="ms-3 text-sm font-medium">{timeMode}</span>
                </label>
                <input
                    type="range"
                    min="0"
                    max="23"
                    value={timeOfDay}
                    onChange={(e) => setTimeOfDay(parseInt(e.target.value))}
                    className="w-full md:w-1/2"
                />
                <span className="text-sm font-mono w-16 text-center">{String(timeOfDay).padStart(2, '0')}:00</span>
            </div>

            <svg viewBox={`0 0 ${width} ${height}`} className="w-full">
                {/* Path */}
                {pathData && <path d={`M ${pathData}`} stroke={isNightMode ? "orange" : "blue"} strokeWidth="1" fill="none" />}

                {/* Special Points */}
                {Object.entries(analemmaData.specialPoints).map(([key, p]) => {
                    if (p.alt < 0) return null;
                    const {x, y} = toSvgCoords(p.az, p.alt);
                    const color = key === 'today' ? (isNightMode ? 'yellow' : 'red') : (isNightMode ? 'cyan' : 'green');
                    return <circle key={key} cx={x} cy={y} r={key === 'today' ? 3 : 2} fill={color} />;
                })}

                {/* Labels */}
                <text x={width/2} y={height-5} textAnchor="middle" fontSize="10" fill={isNightMode ? 'red' : 'black'}>D</text>
                <text x={padding-5} y={height-padding} textAnchor="end" fontSize="10" fill={isNightMode ? 'red' : 'black'}>K</text>
                <text x={width-padding+5} y={height-padding} textAnchor="start" fontSize="10" fill={isNightMode ? 'red' : 'black'}>Ny</text>
                 {[...Array(5)].map((_, i) => (
                   <text key={`l-${i}`} x={padding + (i*45/180)*(width-2*padding)} y={height-padding+12} textAnchor="middle" fontSize="8" fill={isNightMode ? 'red' : 'black'}>{90+i*45}°</text>
                ))}
            </svg>
            <div className={`text-xs flex justify-center gap-4 mt-1 ${textColor}`}>
                <span><span className="text-cyan-400">●</span> Napforduló/Napéjegyenlőség</span>
                <span><span className="text-yellow-400">●</span> Mai pozíció</span>
            </div>
        </div>
    );
};

import React, { useState, useEffect, useMemo } from 'react';
import { useGeolocation } from '../hooks/useGeolocation';
import { AstroObject, LocationData } from '../types';

interface ObjectCatalogProps {
  isNightMode: boolean;
}

// All catalogs point to a single, complete JSON file. Paginated info is removed.
const catalogs = [
    { id: 'Messier', name: 'Messier', path: '/data/messier.json' },
    { id: 'Caldwell', name: 'Caldwell', path: '/data/caldwell.json' },
    { id: 'Melotte', name: 'Melotte', path: '/data/melotte.json' },
    { id: 'NGC', name: 'NGC', path: '/data/ngc.json' } // The new, complete NGC catalog
];

const PAGE_SIZE = 50; // For client-side pagination display

// This hook calculates positions. It runs when objects or location change, or every minute.
const useSkyPositionCalculator = (objects: AstroObject[], location: LocationData | null) => {
    const [positions, setPositions] = useState<{[key: string]: {alt: number | null}}>({});

    useEffect(() => {
        if (!location || objects.length === 0) {
            setPositions({});
            return;
        }

        const DEGREES_TO_RADIANS = Math.PI / 180;
        const RADIANS_TO_DEGREES = 180 / Math.PI;

        const calculatePositions = () => {
            const now = new Date();
            // Simplified and optimized LST calculation for performance with large datasets
            const j2000 = new Date(Date.UTC(2000, 0, 1, 12, 0, 0));
            const diff = now.getTime() - j2000.getTime();
            const d = diff / (1000 * 60 * 60 * 24);
            const ut = now.getUTCHours() + now.getUTCMinutes() / 60 + now.getUTCSeconds() / 3600;
            const gmst = (18.697374558 + 24.06570982441908 * d) % 24;
            let lst_hours = gmst + ut + location.longitude / 15;
            if (lst_hours < 0) lst_hours += 24;
            if (lst_hours >= 24) lst_hours -= 24;

            const lst_rad = lst_hours * 15 * DEGREES_TO_RADIANS;

            const newPositions: {[key: string]: {alt: number | null}} = {};
            const lat_rad = location.latitude * DEGREES_TO_RADIANS;

            objects.forEach(obj => {
                const dec_rad = obj.dec * DEGREES_TO_RADIANS;
                const ra_rad = obj.ra * 15 * DEGREES_TO_RADIANS;
                const ha_rad = lst_rad - ra_rad;

                const sin_alt = Math.sin(dec_rad) * Math.sin(lat_rad) + Math.cos(dec_rad) * Math.cos(lat_rad) * Math.cos(ha_rad);
                const alt_rad = Math.asin(sin_alt);
                newPositions[obj.id] = { alt: alt_rad * RADIANS_TO_DEGREES };
            });
            setPositions(newPositions);
        };

        calculatePositions();
        const interval = setInterval(calculatePositions, 60000); // Recalculate every minute
        return () => clearInterval(interval);

    }, [objects, location]);

    return positions;
};


export const ObjectCatalog: React.FC<ObjectCatalogProps> = ({ isNightMode }) => {
  const { location } = useGeolocation();
  const [searchTerm, setSearchTerm] = useState('');
  const [showVisibleOnly, setShowVisibleOnly] = useState(false);
  const [allObjects, setAllObjects] = useState<AstroObject[]>([]);
  const [loading, setLoading] = useState(false);
  const [selectedCatalog, setSelectedCatalog] = useState(catalogs[0]);
  const [currentPage, setCurrentPage] = useState(1);

  useEffect(() => {
    const fetchObjects = async () => {
        setLoading(true);
        setCurrentPage(1); // Reset pagination
        setSearchTerm(''); // Reset search term
        try {
            const response = await fetch(selectedCatalog.path);
            if (!response.ok) throw new Error(`A ${selectedCatalog.path} betöltése sikertelen.`);
            const data: AstroObject[] = await response.json();
            setAllObjects(data);
        } catch (error) {
            console.error("Failed to fetch catalog data:", error);
            setAllObjects([]);
        } finally {
            setLoading(false);
        }
    };
    fetchObjects();
  }, [selectedCatalog]);

  const positions = useSkyPositionCalculator(allObjects, location);

  const objectsWithPositions = useMemo(() => {
    let results = allObjects.map(obj => ({
        ...obj,
        alt: positions[obj.id]?.alt ?? null
    }));

    if (searchTerm) {
      const lowerCaseSearch = searchTerm.toLowerCase();
      results = results.filter(obj => 
        obj.id.toLowerCase().includes(lowerCaseSearch) || 
        (obj.name && obj.name.toLowerCase().includes(lowerCaseSearch))
      );
    }

    if (showVisibleOnly) {
        results = results.filter(obj => obj.alt !== null && obj.alt > 0);
    }

    return results.sort((a, b) => (b.alt ?? -999) - (a.alt ?? -999));
  }, [searchTerm, showVisibleOnly, allObjects, positions]);


  const totalPages = Math.ceil(objectsWithPositions.length / PAGE_SIZE);
  const paginatedObjects = useMemo(() => {
      const start = (currentPage - 1) * PAGE_SIZE;
      const end = start + PAGE_SIZE;
      return objectsWithPositions.slice(start, end);
  }, [currentPage, objectsWithPositions]);

  useEffect(() => {
    if (currentPage > totalPages && totalPages > 0) {
        setCurrentPage(totalPages);
    } else if (currentPage < 1 && totalPages > 0) {
        setCurrentPage(1);
    }
  }, [currentPage, totalPages]);

  // Reset page to 1 when filters change
  useEffect(() => {
      setCurrentPage(1);
  }, [searchTerm, showVisibleOnly]);

  const handleCatalogChange = (catalogId: string) => {
    const newCatalog = catalogs.find(c => c.id === catalogId);
    if(newCatalog) {
        setSelectedCatalog(newCatalog);
    }
  };

  const cardBg = isNightMode ? 'bg-red-900/20 border-red-800/50' : 'bg-gray-800/50 border-gray-700';
  const inputStyle = "p-2 rounded-md bg-gray-700 border-gray-600 text-white";

  return (
    <div className="animate-fade-in">
      <h2 className={`text-3xl font-bold mb-6 ${isNightMode ? 'text-red-400' : 'text-white'}`}>Objektum Katalógus</h2>
      <div className={`p-4 rounded-lg border ${cardBg} mb-6 flex flex-col sm:flex-row gap-4 items-center`}>
        <select value={selectedCatalog.id} onChange={e => handleCatalogChange(e.target.value)} className={`${inputStyle} sm:w-40`}>
            {catalogs.map(cat => <option key={cat.id} value={cat.id}>{cat.name}</option>)}
        </select>
        <input 
          type="text" 
          placeholder={`Keresés a(z) ${selectedCatalog.name} katalógusban (${allObjects.length} objektum)...`}
          value={searchTerm} 
          onChange={e => setSearchTerm(e.target.value)} 
          className={`${inputStyle} flex-grow`}
        />
        <label className="flex items-center space-x-2 cursor-pointer text-sm">
            <input type="checkbox" checked={showVisibleOnly} onChange={() => setShowVisibleOnly(!showVisibleOnly)} className="form-checkbox h-5 w-5 bg-gray-700 border-gray-600 rounded"/>
            <span>Csak látható</span>
        </label>
      </div>

      {totalPages > 1 && (
        <div className="flex justify-center items-center gap-4 mb-4">
            <button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="px-4 py-2 rounded disabled:opacity-50">‹ Előző</button>
            <span className="text-sm">Oldal {currentPage} / {totalPages} ({objectsWithPositions.length} találat)</span>
            <button onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages} className="px-4 py-2 rounded disabled:opacity-50">Következő ›</button>
        </div>
      )}

      <div className="overflow-x-auto">
        <table className="w-full text-sm text-left">
          <thead className={`${isNightMode ? 'text-red-300' : 'text-gray-300'}`}>
            <tr>
              <th className="p-2">ID</th><th className="p-2">Név</th><th className="p-2">Típus</th>
              <th className="p-2">Csillagkép</th><th className="p-2 text-center">Mag.</th><th className="p-2 text-center">Magasság</th>
            </tr>
          </thead>
          <tbody>
            {loading ? (
                <tr><td colSpan={6} className="text-center p-4">Katalógus betöltése...</td></tr>
            ) : paginatedObjects.length > 0 ? paginatedObjects.map(obj => (
                <ObjectRow key={obj.id} obj={obj} isNightMode={isNightMode} />
            )) : (
                <tr><td colSpan={6} className="text-center p-4">Nincs a szűrésnek megfelelő objektum.</td></tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

const ObjectRow = React.memo(({ obj, isNightMode }: { obj: AstroObject & {alt: number | null}; isNightMode: boolean; }) => {
    const { alt } = obj;
    return (
        <tr className={`border-t ${isNightMode ? 'border-red-800/50' : 'border-gray-700'} ${alt !== null && alt < 0 ? 'opacity-40' : ''}`}>
            <td className="p-2 font-bold">{obj.id}</td><td className="p-2">{obj.name}</td>
            <td className="p-2">{obj.type}</td><td className="p-2">{obj.constellation}</td>
            <td className="p-2 text-center">{obj.magnitude}</td>
            <td className={`p-2 text-center font-medium ${alt === null ? '' : alt > 10 ? (isNightMode ? 'text-green-400' : 'text-green-500') : alt > 0 ? 'text-yellow-500' : (isNightMode ? 'text-red-600': 'text-gray-500')}`}>
                {alt === null ? '...' : `${alt.toFixed(1)}°`}
            </td>
        </tr>
    );
});
